190→    /// Connect to an upstream server with explicit TCP connect timeout.
191→    /// TigerStyle S1: ~2 assertions, S3: bounded operations via Io timeout.
192→    pub fn connectWithTimeout(
193→        self: *Client,
194→        upstream: Upstream,
195→        io: Io,
196→        connect_timeout: Io.Timeout,
197→    ) ClientError!ConnectResult {
198→        // S1: preconditions
199→        assert(upstream.host.len > 0); // S1: non-empty host
200→        assert(upstream.port > 0); // S1: valid port
201→
202→        // Step 1: DNS resolution (timed)
203→        const dns_start_ns = time.monotonicNanos();
204→        const resolve_result = self.dns_resolver.resolve(
205→            upstream.host,
206→            upstream.port,
207→            io,
208→        ) catch {
209→            return ClientError.DnsResolutionFailed;
210→        };
211→        const dns_end_ns = time.monotonicNanos();
212→        const dns_duration_ns = time.elapsedNanos(dns_start_ns, dns_end_ns);
213→
214→        // S2: postcondition - resolved address has correct port
215→        assert(resolve_result.address.getPort() == upstream.port);
