  2→//! TLS Socket Wrapper
  3→//!
  4→//! Wraps serval-tls TLSStream to provide a Socket-compatible interface.
  5→//! TigerStyle: Explicit types, assertions, no runtime allocation after init.
  6→//!
  7→//! Design:
  8→//! - init_client: Client-side TLS handshake with SNI (upstream connections)
  9→//! - init_server: Server-side TLS handshake (client termination)
 10→//! - read/write: Blocking TLS I/O through TLSStream
 11→//! - close: Graceful TLS shutdown + fd close
 12→
 13→const std = @import("std");
 14→const assert = std.debug.assert;
 15→const posix = std.posix;
 16→const serval_core = @import("serval-core");
 17→const closeFd = serval_core.closeFd;
 18→const tls = @import("serval-tls");
 19→const TLSStream = tls.TLSStream;
 20→const ssl = tls.ssl;
 21→
 22→const socket_mod = @import("socket.zig");
 23→pub const SocketError = socket_mod.SocketError;
 24→pub const Socket = socket_mod.Socket;
 25→
 26→/// Maximum hostname length for SNI (RFC 6066 limit).
 27→/// TigerStyle: Named constant with units suffix.
 28→const max_sni_length_chars: u32 = 253;
 29→
 30→/// TLS socket wrapping a TLSStream.
 31→/// TigerStyle: Explicit struct, no hidden state.
 32→pub const TLSSocket = struct {
 33→    /// Underlying file descriptor (exposed for poll/splice operations).
 34→    fd: i32,
 35→
 36→    /// TLS stream for encrypted I/O.
 37→    stream: TLSStream,
 38→
 39→    /// Create client TLS socket with SNI.
 40→    /// Performs TLS handshake with Server Name Indication.
 41→    /// TigerStyle S1: Assertions for preconditions/postconditions.
 42→    /// TigerStyle S5: SNI buffer zeroed, no allocation after init.
 43→    /// enable_ktls: If true (default), attempt kernel TLS offload. If false, use userspace TLS.
 44→    pub fn init_client(
 45→        fd: i32,
 46→        ctx: *ssl.SSL_CTX,
 47→        host: []const u8,
 48→        enable_ktls: bool,
 49→        desired_alpn: ?[]const u8,
 50→    ) SocketError!Socket {
 51→        // S1: preconditions
 52→        assert(fd >= 0); // S1: valid fd
 53→        assert(@intFromPtr(ctx) != 0); // S1: valid ctx pointer
 54→        assert(host.len > 0); // S1: non-empty host
 55→        assert(host.len <= max_sni_length_chars); // S1: host within RFC limit
 56→
 57→        // S5: Stack buffer for null-terminated SNI, zeroed
 58→        var sni_buf: [max_sni_length_chars + 1]u8 = std.mem.zeroes([max_sni_length_chars + 1]u8);
 59→        const host_len: u32 = @intCast(host.len);
 60→        @memcpy(sni_buf[0..host_len], host);
 61→        // Buffer is zeroed, so sni_buf[host_len] is already 0 (null terminator)
 62→
 63→        const sni_z: [*:0]const u8 = @ptrCast(&sni_buf);
 64→
 65→        // TLSStream.initClient uses std.heap.page_allocator internally
 66→        // but we pass a dummy allocator since it's only used for potential
 67→        // future features (we use a non-allocating design)
 68→        const stream = TLSStream.initClient(
 69→            ctx,
 70→            fd,
 71→            sni_z,
 72→            std.heap.page_allocator,
 73→            enable_ktls,
 74→            desired_alpn,
 75→        ) catch |err| {
 76→            return map_tls_error(err);
 77→        };
 78→
 79→        // S1: postcondition - stream initialized with correct fd
 80→        assert(stream.fd == fd);
 81→
 82→        return .{
 83→            .tls = .{
 84→                .fd = fd,
 85→                .stream = stream,
 86→            },
 87→        };
 88→    }
 89→
 90→    /// Create server TLS socket.
 91→    /// Performs TLS handshake for incoming client connection.
 92→    /// TigerStyle S1: Assertions for preconditions/postconditions.
 93→    pub fn init_server(
 94→        fd: i32,
 95→        ctx: *ssl.SSL_CTX,
 96→    ) SocketError!Socket {
 97→        // S1: preconditions
 98→        assert(fd >= 0); // S1: valid fd
 99→        assert(@intFromPtr(ctx) != 0); // S1: valid ctx pointer
100→
101→        const stream = TLSStream.initServer(
102→            ctx,
103→            fd,
104→            std.heap.page_allocator,
105→        ) catch |err| {
106→            return map_tls_error(err);
107→        };
108→
109→        // S1: postcondition - stream initialized with correct fd
110→        assert(stream.fd == fd);
111→
112→        return .{
113→            .tls = .{
114→                .fd = fd,
115→                .stream = stream,
116→            },
117→        };
118→    }
119→
120→    /// Read data through TLS.
121→    /// Returns bytes read, 0 on clean shutdown.
122→    /// TigerStyle S1: Assertions for preconditions/postconditions.
123→    /// TigerStyle S2: Explicit u32 return type.
124→    pub fn read(self: *TLSSocket, buf: []u8) SocketError!u32 {
125→        // S1: preconditions
126→        assert(self.fd >= 0); // S1: socket not closed
127→        assert(buf.len > 0); // S1: non-empty buffer
128→        assert(buf.len <= std.math.maxInt(u32)); // S2: buffer fits in u32
129→
130→        const n = self.stream.read(buf) catch |err| {
131→            return map_tls_error(err);
132→        };
133→
134→        // S2: explicit cast with bounds check
135→        assert(n <= std.math.maxInt(u32));
136→        const bytes_read: u32 = @intCast(n);
137→
138→        // S1: postcondition - bytes read within buffer bounds
139→        assert(bytes_read <= buf.len);
140→
141→        return bytes_read;
142→    }
143→
144→    /// Write data through TLS.
145→    /// Returns bytes written.
146→    /// TigerStyle S1: Assertions for preconditions/postconditions.
147→    /// TigerStyle S2: Explicit u32 return type.
148→    pub fn write(self: *TLSSocket, data: []const u8) SocketError!u32 {
149→        // S1: preconditions
150→        assert(self.fd >= 0); // S1: socket not closed
151→        assert(data.len > 0); // S1: non-empty data
152→        assert(data.len <= std.math.maxInt(u32)); // S2: data fits in u32
153→
154→        const n = self.stream.write(data) catch |err| {
155→            return map_tls_error(err);
156→        };
157→
158→        // S2: explicit cast with bounds check
159→        assert(n <= std.math.maxInt(u32));
160→        const bytes_written: u32 = @intCast(n);
161→
162→        // S1: postcondition - bytes written within data bounds
163→        assert(bytes_written <= data.len);
164→
165→        return bytes_written;
166→    }
167→
168→    /// Returns true if userspace TLS has decrypted bytes buffered internally.
169→    /// Needed for single-threaded tunnel relay correctness: SSL may hold plaintext
170→    /// even when the underlying socket fd is not poll-readable.
171→    pub fn has_pending_read(self: *const TLSSocket) bool {
172→        assert(self.fd >= 0);
173→
174→        return switch (self.stream.mode) {
175→            .ktls => false,
176→            .userspace => |ssl_conn| blk: {
177→                const pending = ssl.SSL_pending(ssl_conn);
178→                assert(pending >= 0);
179→                break :blk pending > 0;
180→            },
181→        };
182→    }
183→
184→    /// Close TLS session and underlying fd.
185→    /// TigerStyle S1: Assertions for preconditions.
186→    pub fn close(self: *TLSSocket) void {
187→        // S1: precondition - socket not already closed
188→        assert(self.fd >= 0);
189→
190→        // Graceful TLS shutdown
191→        self.stream.close();
192→
193→        // Close underlying fd (TLSStream.close() doesn't close it)
194→        closeFd(self.fd);
195→
196→        // Mark as closed
197→        self.fd = -1;
198→    }
199→};
200→
201→/// Map TLS errors to SocketError.
202→/// TigerStyle S6: Explicit error handling, no catch {}.
203→fn map_tls_error(err: anyerror) SocketError {
204→    assert(@errorName(err).len > 0);
205→    return switch (err) {
206→        error.SslNew => SocketError.TLSError,
207→        error.SslSetFd => SocketError.TLSError,
208→        error.SslSetSni => SocketError.TLSError,
209→        error.SslSetAlpn => SocketError.TLSError,
210→        error.InvalidAlpnProtocol => SocketError.TLSError,
211→        error.HandshakeFailed => SocketError.TLSError,
212→        error.SslRead => SocketError.TLSError,
213→        error.SslWrite => SocketError.TLSError,
214→        error.WouldBlock => SocketError.TLSError,
215→        else => SocketError.Unexpected,
216→    };
217→}
