466→
467→    if (session.h2.runtime.state.goaway_sent) return true;
468→    if (session.h2.runtime.state.goaway_received) {
469→        const next_stream_id = session.h2.runtime.state.next_local_stream_id;
470→        if (next_stream_id > session.h2.runtime.state.peer_goaway_last_stream_id and
471→            session.h2.runtime.state.streams.active_count == 0)
