487→
488→    const terminal_flags = posix.POLL.HUP | posix.POLL.ERR | posix.POLL.NVAL;
489→    var poll_fds = [_]posix.pollfd{
490→        .{
491→            .fd = fd,
492→            .events = terminal_flags,
493→            .revents = 0,
494→        },
495→    };
496→
497→    const polled = posix.poll(&poll_fds, 0) catch {
498→        return true;
499→    };
500→    if (polled == 0) return false;
501→
502→    return (poll_fds[0].revents & terminal_flags) != 0;
