505→fn closeSession(session: *?UpstreamSession) void {
506→    assert(@intFromPtr(session) != 0);
507→    assert(session.* == null or session.*.?.generation > 0);
508→
509→    if (session.*) |*inner| {
510→        inner.close();
511→    }
512→    session.* = null;
513→}
514→
515→fn closeSlot(slot: *Slot) void {
516→    assert(@intFromPtr(slot) != 0);
517→    assert(slot.next_generation > 0);
518→
519→    closeSession(&slot.active_session);
520→    closeSession(&slot.draining_session);
521→    slot.* = .{};
522→}
