524→fn testSocketPair(domain: u32, sock_type: u32, protocol: u32) ![2]posix.socket_t {
525→    assert(domain <= std.math.maxInt(c_int));
526→    assert(sock_type <= std.math.maxInt(c_int));
527→
528→    var fds: [2]posix.socket_t = undefined;
529→    var attempts: u32 = 0;
530→    const max_attempts: u32 = 1024;
531→
532→    while (attempts < max_attempts) : (attempts += 1) {
533→        const rc = std.c.socketpair(@intCast(domain), @intCast(sock_type), @intCast(protocol), &fds);
534→        switch (std.c.errno(rc)) {
535→            .SUCCESS => return fds,
536→            .INTR => continue,
537→            else => return error.SocketFailed,
538→        }
539→    }
540→    return error.SocketFailed;
541→}
