404→/// Perform TCP connection using Io async API.
405→/// TigerStyle: Bounded via Io cancellation, explicit error return.
406→fn tcpConnect(address: Io.net.IpAddress, io: Io, connect_timeout: Io.Timeout) !i32 {
407→    // Use IpAddress.connect() to perform async TCP connect
408→    // This creates the socket and connects in one step.
409→    const stream = address.connect(io, .{
410→        .mode = .stream,
411→        .timeout = connect_timeout,
412→    }) catch |err| {
413→        if (err == error.OptionUnsupported and connect_timeout != .none) {
414→            // Some IO backends (notably uring today) do not yet support
415→            // connect-time timeout options. Fall back to backend-default connect
416→            // semantics so callers can still establish connections.
417→            const fallback = address.connect(io, .{
418→                .mode = .stream,
419→                .timeout = .none,
420→            }) catch |fallback_err| {
421→                return fallback_err;
422→            };
423→            return fallback.socket.handle;
424→        }
425→        return err;
426→    };
427→
428→    return stream.socket.handle;
429→}

