319→    pub fn receiveActionIo(self: *ClientConnection, io: Io) Error!runtime_mod.ReceiveAction {
320→        assert(@intFromPtr(self) != 0);
321→        assert(self.socket.get_fd() >= 0);
322→        return self.receiveActionTimeout(io, .none);
323→    }
324→
325→    pub fn receiveActionTimeout(self: *ClientConnection, maybe_io: ?Io, timeout: Io.Timeout) Error!runtime_mod.ReceiveAction {
326→        assert(@intFromPtr(self) != 0);
327→        assert(self.pending_discard_len <= self.recv_len);
328→
329→        self.finalizePendingFrame();
330→        if (self.frame_count >= config.H2_CLIENT_MAX_FRAME_COUNT) return error.FrameLimitExceeded;
331→        if (!try self.ensureFrame(maybe_io, timeout)) return error.ConnectionClosed;
332→
333→        const header = try h2.parseFrameHeader(self.recv_buf[0..h2.frame_header_size_bytes]);
334→        const frame_len: usize = @as(usize, h2.frame_header_size_bytes) + @as(usize, header.length);
335→        const payload_start: usize = h2.frame_header_size_bytes;
336→        const payload_end: usize = frame_len;
337→        const action = try self.runtime.receiveFrame(header, self.recv_buf[payload_start..payload_end]);
338→
339→        self.pending_discard_len = frame_len;
340→        self.frame_count += 1;
341→        return action;
342→    }
343→
344→    pub fn receiveActionHandlingControl(self: *ClientConnection) Error!runtime_mod.ReceiveAction {
345→        assert(@intFromPtr(self) != 0);
346→        assert(config.H2_CLIENT_MAX_FRAME_COUNT > 0);
347→        return self.receiveActionHandlingControlTimeout(null, .none);
348→    }
349→
350→    pub fn receiveActionHandlingControlIo(self: *ClientConnection, io: Io) Error!runtime_mod.ReceiveAction {
351→        assert(@intFromPtr(self) != 0);
352→        assert(self.socket.get_fd() >= 0);
353→        return self.receiveActionHandlingControlTimeout(io, .none);
354→    }
355→
356→    pub fn receiveActionHandlingControlTimeout(
357→        self: *ClientConnection,
358→        maybe_io: ?Io,
359→        timeout: Io.Timeout,
360→    ) Error!runtime_mod.ReceiveAction {
361→        assert(@intFromPtr(self) != 0);
362→        assert(config.H2_CLIENT_MAX_FRAME_COUNT > 0);
363→
364→        var frames: u32 = 0;
365→        while (frames < config.H2_CLIENT_MAX_FRAME_COUNT) : (frames += 1) {
366→            const action = try self.receiveActionTimeout(maybe_io, timeout);
367→            if (try self.handleControlAction(action)) continue;
368→            return action;
369→        }
370→
371→        return error.FrameLimitExceeded;
372→    }
373→
374→    fn handleControlAction(self: *ClientConnection, action: runtime_mod.ReceiveAction) Error!bool {
375→        assert(@intFromPtr(self) != 0);
376→        assert(self.socket.get_fd() >= 0);
377→
378→        switch (action) {
379→            .send_settings_ack => {
380→                self.sendPendingSettingsAck() catch |err| switch (err) {
381→                    error.ConnectionClosed => {},
382→                    else => return err,
383→                };
384→            },
385→            .send_ping_ack => |opaque_data| {
386→                self.sendPingAck(opaque_data) catch |err| switch (err) {
387→                    error.ConnectionClosed => {},
388→                    else => return err,
389→                };
390→            },
391→            else => return false,
392→        }
393→
394→        return true;
395→    }
396→
397→    fn ensureFrame(self: *ClientConnection, maybe_io: ?Io, timeout: Io.Timeout) Error!bool {
398→        assert(@intFromPtr(self) != 0);
399→        assert(self.recv_len <= self.recv_buf.len);
400→
401→        if (self.recv_len == 0) {
402→            const n = try self.readIntoBuffer(maybe_io, timeout);
403→            if (n == 0) return false;
404→        }
405→
406→        try self.fillBuffer(maybe_io, timeout, h2.frame_header_size_bytes);
407→        const header = try h2.parseFrameHeader(self.recv_buf[0..h2.frame_header_size_bytes]);
408→        const frame_len: usize = @as(usize, h2.frame_header_size_bytes) + @as(usize, header.length);
409→        try self.fillBuffer(maybe_io, timeout, frame_len);
410→        return true;
411→    }
412→
413→    fn fillBuffer(self: *ClientConnection, maybe_io: ?Io, timeout: Io.Timeout, needed_len: usize) Error!void {
414→        assert(@intFromPtr(self) != 0);
415→        assert(needed_len <= self.recv_buf.len);
416→
417→        var reads: u32 = 0;
418→        while (self.recv_len < needed_len and reads < self.recv_buf.len) : (reads += 1) {
419→            const n = try self.readIntoBuffer(maybe_io, timeout);
420→            if (n == 0) return error.ConnectionClosed;
421→        }
422→
423→        if (self.recv_len < needed_len) return error.ReadFailed;
424→    }
425→
426→    fn readIntoBuffer(self: *ClientConnection, maybe_io: ?Io, timeout: Io.Timeout) Error!usize {
427→        assert(@intFromPtr(self) != 0);
428→        assert(self.recv_len <= self.recv_buf.len);
429→
430→        const n = try readSome(self.socket, maybe_io, timeout, self.recv_buf[self.recv_len..]);
431→        if (n == 0) return 0;
432→
433→        self.recv_len += n;
434→        assert(self.recv_len <= self.recv_buf.len);
435→        return n;
436→    }
437→
438→    fn finalizePendingFrame(self: *ClientConnection) void {
439→        assert(@intFromPtr(self) != 0);
440→        assert(self.pending_discard_len <= self.recv_len);
441→
442→        if (self.pending_discard_len == 0) return;
443→        self.discardPrefix(self.pending_discard_len);
444→        self.pending_discard_len = 0;
445→    }
446→
447→    fn discardPrefix(self: *ClientConnection, prefix_len: usize) void {
448→        assert(@intFromPtr(self) != 0);
449→        assert(prefix_len <= self.recv_len);
450→
451→        if (prefix_len == self.recv_len) {
452→            self.recv_len = 0;
453→            return;
454→        }
455→
456→        std.mem.copyForwards(u8, self.recv_buf[0 .. self.recv_len - prefix_len], self.recv_buf[prefix_len..self.recv_len]);
457→        self.recv_len -= prefix_len;
458→    }
459→
460→    fn writeAll(self: *ClientConnection, data: []const u8) Error!void {
461→        assert(@intFromPtr(self) != 0);
462→        assert(self.socket.get_fd() >= 0);
463→
464→        switch (self.socket.*) {
465→            .plain => |plain| {
466→                if (self.io) |io| {
467→                    var write_buf: [config.STREAM_WRITE_BUFFER_SIZE_BYTES]u8 = undefined;
468→                    var writer = rawStreamForFd(plain.fd).writer(io, &write_buf);
469→                    writer.interface.writeAll(data) catch return mapIoWriteError(writer.err orelse error.WriteFailed);
470→                    writer.interface.flush() catch return mapIoWriteError(writer.err orelse error.WriteFailed);
471→                    return;
472→                }
473→
474→                self.socket.write_all(data) catch |err| return mapWriteError(err);
475→            },
476→            .tls => {
477→                self.socket.write_all(data) catch |err| return mapWriteError(err);
478→            },
479→        }
480→    }
481→};
482→
483→fn readSome(socket: *Socket, maybe_io: ?Io, timeout: Io.Timeout, out: []u8) Error!u32 {
484→    assert(@intFromPtr(socket) != 0);
485→    assert(out.len > 0);
486→
487→    return switch (socket.*) {
488→        .plain => |*plain| blk: {
489→            if (maybe_io) |io| {
490→                if (timeout != .none) {
491→                    try waitUntilReadable(plain.fd, io, timeout);
492→                }
493→                var bufs: [1][]u8 = .{out};
494→                const n = io.vtable.netRead(io.userdata, plain.fd, &bufs) catch |err| switch (err) {
495→                    error.ConnectionResetByPeer,
496→                    error.SocketUnconnected,
497→                    => return error.ConnectionClosed,
498→                    error.SystemResources => return error.WouldBlock,
499→                    else => return error.ReadFailed,
500→                };
501→                break :blk @intCast(n);
502→            }
503→            const n = plain.read(out) catch |err| return mapReadError(err);
504→            break :blk n;
505→        },
506→        .tls => |*tls_socket| blk: {
507→            if (tls_socket.has_pending_read()) {
508→                const n = tls_socket.stream.read(out) catch |err| switch (err) {
509→                    error.WantRead, error.WantWrite => return error.WouldBlock,
510→                    else => return error.ReadFailed,
511→                };
512→                break :blk n;
513→            }
514→
515→            if (maybe_io) |io| {
516→                try waitUntilReadable(tls_socket.fd, io, timeout);
517→            }
518→            const n = tls_socket.stream.read(out) catch |err| switch (err) {
519→                error.WantRead, error.WantWrite => return error.WouldBlock,
520→                error.ConnectionReset => return error.ConnectionClosed,
521→                else => return error.ReadFailed,
522→            };
523→            break :blk n;
524→        },
525→    };
526→}
