528→fn waitUntilReadable(fd: i32, io: Io, timeout: Io.Timeout) Error!void {
529→    assert(fd >= 0);
530→    assert(rawStreamForFd(fd).socket.handle == fd);
531→
532→    var messages: [1]Io.net.IncomingMessage = .{Io.net.IncomingMessage.init};
533→    var peek_buf: [1]u8 = undefined;
534→    const maybe_err, _ = rawStreamForFd(fd).socket.receiveManyTimeout(
535→        io,
536→        &messages,
537→        &peek_buf,
538→        .{ .peek = true },
539→        timeout,
540→    );
541→    if (maybe_err) |err| switch (err) {
542→        error.Timeout => return error.WouldBlock,
543→        error.ConnectionResetByPeer => return error.ConnectionClosed,
544→        else => return error.ReadFailed,
545→    };
546→}
547→
548→fn rawStreamForFd(fd: i32) Io.net.Stream {
549→    assert(fd >= 0);
550→    const stream: Io.net.Stream = .{
551→        .socket = .{
552→            .handle = fd,
553→            .address = .{ .ip4 = .unspecified(0) },
554→        },
555→    };
556→    assert(stream.socket.handle == fd);
557→    return stream;
558→}
