561→    const mapped: Error = switch (err) {
562→        error.ConnectionClosed,
563→        error.ConnectionReset,
564→        => error.ConnectionClosed,
565→        else => error.ReadFailed,
566→    };
567→    assert(mapped != error.WriteFailed);
568→    assert(mapped == error.ConnectionClosed or mapped == error.ReadFailed);
