660→fn readExact(fd: i32, out: []u8) !void {
661→    assert(fd >= 0);
662→
663→    var offset: usize = 0;
664→    var reads: usize = 0;
665→    const max_reads: usize = std.math.add(usize, out.len, 32) catch return error.ReadFailed;
