 35→const std = @import("std");
 36→const assert = std.debug.assert;
 37→
 38→/// Parse IPv4 address string to network-order u32.
 39→/// Returns null for invalid addresses.
 40→pub fn parse_ipv4(host: []const u8) ?u32 {
 41→    if (host.len == 0) return null;
 42→    if (host.len > 15) return null; // "255.255.255.255" = 15 chars max
 43→
 44→    assert(host.len <= 15);
 45→    const host_len: u8 = @intCast(host.len);
 46→
 47→    var octets: [4]u8 = std.mem.zeroes([4]u8);
 48→    var octet_idx: u8 = 0;
 49→    var current_value: u16 = 0;
 50→    var digit_count: u8 = 0;
 51→
 52→    const max_iterations: u8 = 16;
 53→    var iterations: u8 = 0;
 54→
 55→    var index: u8 = 0;
 56→    while (index < host_len) : (index += 1) {
 57→        if (iterations >= max_iterations) return null;
 58→        iterations += 1;
 59→
 60→        const ch = host[index];
 61→        if (ch == '.') {
 62→            if (digit_count == 0) return null;
 63→            if (current_value > 255) return null;
 64→            if (octet_idx >= 3) return null;
 65→
 66→            octets[@intCast(octet_idx)] = @intCast(current_value);
 67→            octet_idx += 1;
 68→            current_value = 0;
 69→            digit_count = 0;
 70→        } else if (ch >= '0' and ch <= '9') {
 71→            current_value = current_value * 10 + @as(u16, ch - '0');
 72→            digit_count += 1;
 73→            if (digit_count > 3) return null;
 74→        } else {
 75→            return null;
 76→        }
 77→    }
 78→
 79→    // Final octet
 80→    if (digit_count == 0) return null;
 81→    if (current_value > 255) return null;
 82→    if (octet_idx != 3) return null;
 83→
 84→    octets[3] = @intCast(current_value);
 85→
 86→    assert(octet_idx == 3);
 87→    assert(iterations <= max_iterations);
 88→    return @as(u32, octets[0]) |
 89→        (@as(u32, octets[1]) << 8) |
 90→        (@as(u32, octets[2]) << 16) |
 91→        (@as(u32, octets[3]) << 24);
 92→}
