  3→//!
  4→//! TCP socket configuration helpers (Nagle, keepalive, linger).
  5→//! TigerStyle: Small focused functions, explicit error handling.
  6→
  7→const std = @import("std");
  8→const log = @import("serval-core").log.scoped(.net);
  9→const assert = std.debug.assert;
 10→const posix = std.posix;
 11→
 12→// Verify TCP protocol number at comptime (defense in depth)
 13→comptime {
 14→    assert(posix.IPPROTO.TCP == 6);
 15→}
 16→
 17→/// Disable Nagle's algorithm on a TCP socket.
 18→/// Prevents 40ms delay when sending small packets (Nagle + delayed ACKs).
 19→/// Returns true if successful, false if setsockopt failed.
 20→/// TigerStyle: Explicit return value instead of swallowing errors.
 21→pub fn set_tcp_no_delay(fd: i32) bool {
 22→    // Precondition: fd must be >= -1 (-1 is valid "skip" sentinel, < -1 is programming error)
 23→    assert(fd >= -1);
 24→
 25→    // No-op for invalid fd sentinel, not an error
 26→    if (fd < 0) return true;
 27→
 28→    // Use native endianness - setsockopt expects host byte order for integer options
 29→    const enabled: u32 = 1;
 30→    const value_bytes = std.mem.asBytes(&enabled);
 31→
 32→    posix.setsockopt(fd, posix.IPPROTO.TCP, posix.TCP.NODELAY, value_bytes) catch |err| {
 33→        // Log at debug level - this is an optimization, not critical
 34→        // TigerStyle: Explicit error handling instead of catch {}
 35→        log.debug("set_tcp_no_delay failed on fd {d}: {s}", .{ fd, @errorName(err) });
 36→        return false;
 37→    };
 38→
 39→    return true;
 40→}
