 42→/// Configure TCP keepalive on a socket.
 43→/// Sends probes after idle_secs of inactivity, then every interval_secs,
 44→/// closing after count failed probes.
 45→/// Returns true if all options set successfully.
 46→/// TigerStyle: Explicit parameters, no magic defaults.
 47→pub fn set_tcp_keep_alive(
 48→    fd: i32,
 49→    idle_secs: u32,
 50→    interval_secs: u32,
 51→    count: u32,
 52→) bool {
 53→    // Preconditions: valid fd and positive timing values
 54→    assert(fd >= 0);
 55→    assert(idle_secs > 0);
 56→    assert(interval_secs > 0);
 57→    assert(count > 0);
 58→
 59→    // Enable keepalive
 60→    const enabled: u32 = 1;
 61→    posix.setsockopt(fd, posix.SOL.SOCKET, posix.SO.KEEPALIVE, std.mem.asBytes(&enabled)) catch |err| {
 62→        log.debug("set_tcp_keep_alive SO_KEEPALIVE failed on fd {d}: {s}", .{ fd, @errorName(err) });
 63→        return false;
 64→    };
 65→
 66→    // Set timing parameters (Linux only - other platforms use system defaults)
 67→    if (@import("builtin").os.tag == .linux) {
 68→        // TCP_KEEPIDLE: idle time before first probe
 69→        posix.setsockopt(fd, posix.IPPROTO.TCP, posix.TCP.KEEPIDLE, std.mem.asBytes(&idle_secs)) catch |err| {
 70→            log.debug("set_tcp_keep_alive KEEPIDLE failed on fd {d}: {s}", .{ fd, @errorName(err) });
 71→            return false;
 72→        };
 73→
 74→        // TCP_KEEPINTVL: interval between probes
 75→        posix.setsockopt(fd, posix.IPPROTO.TCP, posix.TCP.KEEPINTVL, std.mem.asBytes(&interval_secs)) catch |err| {
 76→            log.debug("set_tcp_keep_alive KEEPINTVL failed on fd {d}: {s}", .{ fd, @errorName(err) });
 77→            return false;
 78→        };
 79→
 80→        // TCP_KEEPCNT: probe count before declaring dead
 81→        posix.setsockopt(fd, posix.IPPROTO.TCP, posix.TCP.KEEPCNT, std.mem.asBytes(&count)) catch |err| {
 82→            log.debug("set_tcp_keep_alive KEEPCNT failed on fd {d}: {s}", .{ fd, @errorName(err) });
 83→            return false;
 84→        };
 85→    }
 86→    // On non-Linux, only SO_KEEPALIVE is set (uses system defaults for timing)
 87→
 88→    return true;
 89→}
