 91→/// Disable delayed ACKs on a TCP socket (Linux only).
 92→/// Reduces latency at cost of more ACK packets.
 93→/// Returns true if successful (or not Linux).
 94→/// TigerStyle: Explicit opt-in for latency optimization.
 95→pub fn set_tcp_quick_ack(fd: i32) bool {
 96→    // Precondition: valid fd
 97→    assert(fd >= 0);
 98→
 99→    if (@import("builtin").os.tag != .linux) return true;
100→
101→    const enabled: u32 = 1;
102→    posix.setsockopt(fd, posix.IPPROTO.TCP, posix.TCP.QUICKACK, std.mem.asBytes(&enabled)) catch |err| {
103→        log.debug("set_tcp_quick_ack failed on fd {d}: {s}", .{ fd, @errorName(err) });
104→        return false;
105→    };
106→    return true;
107→}
108→
109→/// Configure SO_LINGER on a socket.
110→/// If timeout_secs > 0, close() blocks up to timeout_secs waiting for data to send.
111→/// If timeout_secs = 0, close() returns immediately with RST, unsent data lost.
112→/// Returns true if successful.
113→/// TigerStyle: Explicit close behavior, no implicit blocking.
114→pub fn set_so_linger(fd: i32, timeout_secs: u16) bool {
115→    // Precondition: valid fd
116→    assert(fd >= 0);
117→
118→    const linger_val = posix.linger{
119→        .onoff = if (timeout_secs > 0) 1 else 0,
120→        .linger = @intCast(timeout_secs),
121→    };
122→    posix.setsockopt(fd, posix.SOL.SOCKET, posix.SO.LINGER, std.mem.asBytes(&linger_val)) catch |err| {
123→        log.debug("set_so_linger failed on fd {d}: {s}", .{ fd, @errorName(err) });
124→        return false;
125→    };
126→    return true;
127→}
