355→    pub fn parse(buffer: []const u8, port: u16) ParseError!Ip4Address {
356→        var bytes: [4]u8 = @splat(0);
357→        var index: u8 = 0;
358→        var saw_any_digits = false;
359→        var has_zero_prefix = false;
360→        for (buffer) |c| switch (c) {
361→            '.' => {
362→                if (!saw_any_digits) return error.InvalidCharacter;
363→                if (index == 3) return error.InvalidEnd;
364→                index += 1;
365→                saw_any_digits = false;
366→                has_zero_prefix = false;
367→            },
368→            '0'...'9' => {
369→                if (c == '0' and !saw_any_digits) {
370→                    has_zero_prefix = true;
371→                } else if (has_zero_prefix) {
372→                    return error.NonCanonical;
373→                }
374→                saw_any_digits = true;
375→                bytes[index] = try std.math.mul(u8, bytes[index], 10);
376→                bytes[index] = try std.math.add(u8, bytes[index], c - '0');
377→            },
378→            else => return error.InvalidCharacter,
379→        };
380→        if (index == 3 and saw_any_digits) return .{
381→            .bytes = bytes,
382→            .port = port,
383→        };
384→        return error.Incomplete;
385→    }
