5167→fn netConnectIp(
5168→    userdata: ?*anyopaque,
5169→    address: *const net.IpAddress,
5170→    options: net.IpAddress.ConnectOptions,
5171→) net.IpAddress.ConnectError!net.Stream {
5172→    if (options.timeout != .none) return error.OptionUnsupported;
5173→    const ev: *Evented = @ptrCast(@alignCast(userdata));
5174→    const family = posixAddressFamily(address);
5175→    var maybe_sync: CancelRegion.Sync.Maybe = .{ .cancel_region = .init() };
5176→    defer maybe_sync.deinit(ev);
5177→    const socket_fd = try ev.socket(&maybe_sync.cancel_region, family, .{
5178→        .mode = options.mode,
5179→        .protocol = options.protocol,
5180→    });
5181→    errdefer ev.closeAsync(socket_fd);
5182→
5183→    var storage: PosixAddress = undefined;
5184→    var addr_len = addressToPosix(address, &storage);
5185→    try ev.connect(&maybe_sync.cancel_region, socket_fd, &storage.any, addr_len);
5186→    try ev.getsockname(try maybe_sync.enterSync(ev), socket_fd, &storage.any, &addr_len);
5187→    return .{ .socket = .{
5188→        .handle = socket_fd,
5189→        .address = addressFromPosix(&storage),
5190→    } };
5191→}
