5259→        .namelen = addressToPosix(message.address, &addr),
5260→        .iov = (&iov)[0..1],
5261→        .iovlen = 1,
5262→        .control = if (message.control.len == 0) null else message.control.ptr,
5263→        .controllen = message.control.len,
5264→        .flags = 0,
5265→    };
5266→
5267→    while (true) {
5268→        const thread = try cancel_region.awaitIoUring();
5269→        thread.enqueue().* = .{
5270→            .opcode = .SENDMSG,
5271→            .flags = 0,
5272→            .ioprio = 0,
5273→            .fd = handle,
5274→            .off = 0,
5275→            .addr = @intFromPtr(&msg),
5276→            .len = 1,
5277→            .rw_flags = flags,
5278→            .user_data = @intFromPtr(cancel_region.fiber),
5279→            .buf_index = 0,
5280→            .personality = 0,
5281→            .splice_fd_in = 0,
5282→            .addr3 = 0,
5283→            .resv = 0,
5284→        };
